
import { defineComponent, onMounted, reactive, ref, toRefs, watch } from "vue";
import { useRouter } from "vue-router";

import Searchentrust from "../../../components/ATaskdelegation/Taskallocation/Searchentrust.vue";
import Tableentrust from "../../../components/ATaskdelegation/Taskallocation/Tableentrust.vue";
import {
  get_entrust_history,
  getEntrustHistoryDetail,
  abandonEntrust,
} from "../../../server/http/api/user";
import { addKey } from "../../../utils/addKey";
export default defineComponent({
  name: "EntrustSearch",
  components: { Searchentrust, Tableentrust },
  setup() {
    const entrustList: any = ref();
    const router = useRouter();
    const total = ref(0);
    let searchOptions = reactive({
      pageNum: 1,
      pageSize: 10,
      state: 0,
    });
    // 历史委托列表
    onMounted(() => {});
    function search() {
      get_entrust_history(searchOptions).then((res: any) => {
        if (res.data.code === 200) {
          //console.log(res.data.data.list);

          entrustList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    watch(
      searchOptions,
      () => {
        search();
      },
      {
        immediate: true,
      }
    );
    const searchEntrust = function (formState: any) {
      Object.assign(searchOptions, formState);
    };

    // 委托单详情
    const routerEntrustDetail = function (id: number) {
      router.push({
        name: "entrustDetail",
        params: { id },
      });
    };
    // 委托单修改
    const routerEntrustUpdate = function (id: number) {
      getEntrustHistoryDetail(id).then((res: any) => {
        if (res.data.code === 200) {
          localStorage.setItem("entrust", JSON.stringify(res.data.data));
          router.push({
            name: "EntrustUpdate",
          });
        }
      });
    };
    // 委托单作废
    const abandonEntrustRemove = function (options: any) {
      abandonEntrust(options).then((res: any) => {
        //console.log("委托单作废", res);
        search();
      });
    };
    return {
      routerEntrustDetail,
      routerEntrustUpdate,
      abandonEntrustRemove,
      searchEntrust,
      entrustList,
      ...toRefs(searchOptions),
      total,
    };
  },
});
