
import { SmileOutlined, DownOutlined } from "@ant-design/icons-vue";
import { defineComponent, reactive, ref, toRefs } from "vue";

const columns = [
  {
    dataIndex: "entrustmentNo",
    key: "entrustmentNo",
    title: "委托编号",
  },
  {
    title: "委托单位",
    dataIndex: "entrustCompany",
    key: "entrustCompany",
  },
  {
    title: "委托人",
    dataIndex: "entrustPeople",
    key: "entrustPeople",
  },
  {
    title: "受理人",
    key: "businessAcceptor",
    dataIndex: "businessAcceptor",
  },
  {
    title: "受理日期",
    key: "acceptanceDate",
    dataIndex: "acceptanceDate",
  },

  // {
  //   title: "样品状态",
  //   key: "state",
  //   dataIndex: "state",
  //   slots: { customRender: "state" },
  // },
  // {
  //   title: "样品状态",
  //   key: "state",
  //   dataIndex: "state",
  //   slots: { customRender: "state" },
  // },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

export default defineComponent({
  props: ["entrust"],
  setup(props, ctx) {
    const visible = ref<boolean>(false);
    let data: any = reactive({
      invalidReason: "",
      id: null,
    });
    let desc = ref("");
    const routerEntrustDetail = function (id: number) {
      ctx.emit("routerEntrustDetail", id);
    };
    const routerEntrustUpdate = function (id: number) {
      ctx.emit("routerEntrustUpdate", id);
    };

    const abandonEntrust = function (id: number) {
      data.id = id;
      visible.value = true;
    };
    const handleOk = function () {
      //console.log(data);

      ctx.emit("abandonEntrustRemove", {
        id: data.id,
        invalidReason: data.invalidReason,
      });
      data.invalidReason = "";
      visible.value = false;
    };
    return {
      data,
      routerEntrustDetail,
      routerEntrustUpdate,
      abandonEntrust,
      handleOk,
      columns,
      visible,
      desc,
    };
  },
  components: {
    SmileOutlined,
    DownOutlined,
  },
});
