
import { getTime } from "@/utils/getTime";
import { defineComponent, reactive, toRaw, toRefs, watch } from "vue";
import { get_select_value } from "../../../server/http/api/user";
export default defineComponent({
  setup(props, ctx) {
    const formState: any = reactive({
      entrustmentNo: null,
      sampleName: null,
      businessAcceptor: null,
      dateInterval: [],
      state: 0,
      entrustPeople: "",
    });

    let timer: any;
    watch(formState, (newval, o) => {
      clearTimeout(timer);

      timer = setTimeout(() => {
        if (formState.dateInterval.length !== 0) {
          ctx.emit("searchEntrust", {
            ...formState,
            dateInterval: `${getTime(formState.dateInterval[0])}~${getTime(
              formState.dateInterval[1]
            )}`,
          });
        } else {
          ctx.emit("searchEntrust", { ...formState, dateInterval: null });
        }
      }, 600);
    });

    return {
      ...toRefs(formState),
    };
  },
});
